class Solution:
    def solve(self, board):
        if not board or not board[0]:
            return
        m, n = len(board), len(board[0])
        safe = [[False] * n for _ in range(m)]
        from collections import deque
        q = deque()
        for i in range(m):
            for j in range(n):
                on_border = i == 0 or j == 0 or i == m - 1 or j == n - 1
                if on_border and board[i][j] == 'O':
                    safe[i][j] = True
                    q.append((i, j))
        while q:
            i, j = q.popleft()
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and not safe[ni][nj] and board[ni][nj] == 'O':
                    safe[ni][nj] = True
                    q.append((ni, nj))
        for i in range(m):
            for j in range(n):
                if board[i][j] == 'O' and not safe[i][j]:
                    board[i][j] = 'X'

